sql:
SELECT performance_score
FROM performance_scores
ORDER BY year DESC;

SELECT policy_name, policy_status 
FROM governance
WHERE policy_status = 'Active';

SELECT s.school_id, s.school_name
FROM schools s
WHERE EXISTS (
    SELECT 1 FROM parent_communication pc
    WHERE pc.school_id = s.school_id
)
AND EXISTS (
    SELECT 1 FROM self_evaluation se
    WHERE se.school_id = s.school_id
);

SELECT policy_status 
FROM governance 
WHERE LENGTH(policy_name) = (
    SELECT MAX(LENGTH(policy_name))
    FROM governance
);

SELECT category_id, category_name, description, weightage,
       DENSE_RANK() OVER (ORDER BY weightage DESC) as rank
FROM performance_categories;

SELECT * 
FROM performance_categories 
WHERE weightage > 50;

SELECT teacher_id 
FROM teacher_evaluation 
WHERE evaluation_score > 80;

SELECT schools.school_name, student_performance.student_name, student_performance.performance_score 
FROM schools
JOIN student_performance ON schools.school_id = student_performance.school_id;

SELECT AVG(performance_score) AS average_performance
FROM student_performance
WHERE school_id = 1;

SELECT COUNT(*)
FROM teacher_evaluation
WHERE evaluation_score BETWEEN '8' AND '10';

SELECT users.user_name, users.email, users.role, users.designation
FROM users
INNER JOIN schools ON users.school_id = schools.school_id;

SELECT s.school_name
FROM schools s
WHERE s.school_id IN (
    SELECT ps.school_id
    FROM performance_scores ps
) 
AND s.school_id NOT IN (
    SELECT pr.school_id
    FROM performance_reports pr
);

SELECT category_name, weightage
FROM performance_categories
ORDER BY weightage DESC;
